   418→let allRows     = [];
   419→let TERMINAL    = [];
   420→let VPERKS      = {};
   421→let TOTAL_VARS  = 61;
   422→let filterMode  = 'all';
   423→let rarityFilter = null;
   424→let sortMode    = 'default';
   425→let myDust      = 0;
   426→let basketQty   = {};
   427→
   428→const RARITY_ORDER = ['Rare','Epic','Legendary','Mythic'];
   429→const RARITY_ICONS = { Rare:'💧', Epic:'⚡', Legendary:'🔥', Mythic:'🌌' };
   430→
   431→/* ════════════════════════════════════════════════════════════
   432→   Boot
   433→════════════════════════════════════════════════════════════ */
   434→async function boot() {
   435→  const saved = localStorage.getItem('myDust');
   436→  if (saved) { myDust = parseInt(saved)||0; document.getElementById('myDustInput').value = myDust; }
   437→  const sb = localStorage.getItem('basket');
   438→  if (sb) { try { basketQty = JSON.parse(sb); } catch(e){} }
   439→
   440→  const [dirRes, colRes] = await Promise.all([fetch('/api/directory'), fetch('/api/collection')]);
   441→  const dir = await dirRes.json();
   442→  const col = await colRes.json();
   443→
   444→  TERMINAL   = dir.terminal;
   445→  VPERKS     = dir.variant_perks;
   446→  TOTAL_VARS = dir.total_variants || 61;
   447→  allRows    = col.rows;
   448→
   449→  updateStats(col.stats);
   450→  render();
   451→  renderTerminal();
   452→  renderCalculator();
   453→}
