   455→/* ════════════════════════════════════════════════════════════
   456→   Dust
   457→════════════════════════════════════════════════════════════ */
   458→function onDustChange() {
   459→  myDust = parseInt(document.getElementById('myDustInput').value)||0;
   460→  localStorage.setItem('myDust', myDust);
   461→  renderCalculator();
   462→}
   463→
   464→/* ════════════════════════════════════════════════════════════
   465→   Tabs / Filters / Sort
   466→════════════════════════════════════════════════════════════ */
   467→function switchTab(name, btn) {
   468→  document.querySelectorAll('.tab-panel').forEach(p => p.classList.remove('active'));
   469→  document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
   470→  document.getElementById('tab-'+name).classList.add('active');
   471→  btn.classList.add('active');
   472→}
   473→
   474→function setFilter(mode, btn) {
   475→  filterMode = mode;
   476→  document.querySelectorAll('[data-filter]').forEach(b => b.classList.remove('active'));
   477→  btn.classList.add('active');
   478→  render();
   479→}
   480→
   481→function setRarity(r, btn) {
   482→  if (rarityFilter === r) {
   483→    rarityFilter = null;
   484→    document.querySelectorAll('.rarity-filter').forEach(b => { b.className='filter-btn rarity-filter'; });
   485→  } else {
   486→    rarityFilter = r;
   487→    document.querySelectorAll('.rarity-filter').forEach(b => { b.className='filter-btn rarity-filter'; });
   488→    btn.classList.add('active-'+r);
   489→  }
   490→  render();
   491→}
   492→
   493→function setSort(mode, btn) {
   494→  sortMode = mode;
   495→  document.querySelectorAll('.sort-btn').forEach(b => b.classList.remove('active'));
   496→  btn.classList.add('active');
   497→  render();
   498→}
   499→
   500→/* ════════════════════════════════════════════════════════════
   501→   Sort helper
   502→════════════════════════════════════════════════════════════ */
   503→function applySort(rows) {
   504→  const VARIANTS_ORDER = ['Normal','Gold','Gummy','Galaxy'];
   505→  if (sortMode === 'default') {
   506→    return [...rows].sort((a,b) =>
   507→      RARITY_ORDER.indexOf(a.rarity) - RARITY_ORDER.indexOf(b.rarity) ||
   508→      a.name.localeCompare(b.name) ||
   509→      VARIANTS_ORDER.indexOf(a.variant) - VARIANTS_ORDER.indexOf(b.variant)
   510→    );
   511→  }
   512→  if (sortMode === 'lvl-desc') {
   513→    return [...rows].sort((a,b) => b.level - a.level || a.name.localeCompare(b.name));
   514→  }
   515→  if (sortMode === 'lvl-asc') {
   516→    return [...rows].sort((a,b) => a.level - b.level || a.name.localeCompare(b.name));
   517→  }
   518→  if (sortMode === 'mastered') {
   519→    return [...rows].sort((a,b) => (b.mastered?1:0) - (a.mastered?1:0) || b.level - a.level || a.name.localeCompare(b.name));
   520→  }
   521→  return rows;
   522→}
   523→
   524→/* ════════════════════════════════════════════════════════════
   525→   Render collection
   526→════════════════════════════════════════════════════════════ */
   527→function render() {
   528→  let rows = allRows;
   529→  if (rarityFilter)            rows = rows.filter(r => r.rarity === rarityFilter);
   530→  if (filterMode === 'owned')   rows = rows.filter(r => r.owned);
   531→  if (filterMode === 'unowned') rows = rows.filter(r => !r.owned);
   532→  if (filterMode === 'mastered') rows = rows.filter(r => r.mastered);
   533→  rows = applySort(rows);
   534→
   535→  if (!rows.length) {
   536→    document.getElementById('list').innerHTML = '<div class="center-msg">No sprites match the current filter.</div>';
   537→    return;
   538→  }
   539→
   540→  // When sorting by level, group differently (flat list within rarity groups)
   541→  const useRarityGroups = (sortMode === 'default' || rarityFilter);
   542→
   543→  if (useRarityGroups) {
   544→    renderGrouped(rows);
   545→  } else {
   546→    renderFlat(rows);
   547→  }
   548→}
   549→
   550→function renderGrouped(rows) {
   551→  const grouped = {};
   552→  for (const r of rows) {
   553→    grouped[r.rarity]       = grouped[r.rarity] || {};
   554→    grouped[r.rarity][r.name] = grouped[r.rarity][r.name] || [];
   555→    grouped[r.rarity][r.name].push(r);
   556→  }
   557→  let html = '';
   558→  for (const rarity of RARITY_ORDER) {
   559→    if (!grouped[rarity]) continue;
   560→    const spriteNames = Object.keys(grouped[rarity]);
   561→    html += `<div class="rarity-header ${rarity}">${RARITY_ICONS[rarity]} ${rarity.toUpperCase()} <span>(${spriteNames.length} sprite${spriteNames.length>1?'s':''})</span></div>`;
   562→    for (const name of spriteNames) {
   563→      html += buildSpriteBlock(name, grouped[rarity][name]);
   564→    }
   565→  }
   566→  document.getElementById('list').innerHTML = html;
   567→}
   568→
   569→function renderFlat(rows) {
   570→  // Group by sprite name for level guide, but list in sorted order
   571→  const seen = new Set();
   572→  const blocks = [];
   573→  for (const r of rows) {
   574→    if (!seen.has(r.name)) {
   575→      seen.add(r.name);
   576→      blocks.push({ name: r.name, rows: rows.filter(x => x.name === r.name) });
   577→    }
   578→  }
   579→  let html = '';
   580→  for (const b of blocks) {
   581→    html += `<div style="margin-top:8px">` + buildSpriteBlock(b.name, b.rows) + `</div>`;
   582→  }
   583→  document.getElementById('list').innerHTML = html;
   584→}
   585→
   586→function buildSpriteBlock(spriteName, variants) {
   587→  const ability   = variants[0].ability;
   588→  const levelData = variants[0].levels;
   589→  const sid       = safeId(spriteName);
   590→
   591→  let levelRows = '<div class="lvl-desc-rows">';
   592→  for (let i = 1; i <= 5; i++) {
   593→    levelRows += `<div class="lvl-desc-row">
   594→      <div class="lvl-num ${i===5?'m':''}">${i===5?'★':i}</div>
   595→      <div class="lvl-desc ${i===5?'m':''}">${esc(levelData[i]||'')}</div>
   596→    </div>`;
   597→  }
   598→  levelRows += '</div>';
   599→
   600→  let variantRows = variants.map(r => buildVariantRow(r)).join('');
   601→
   602→  return `<div class="sprite-block">
   603→    <div class="sprite-label-row">
   604→      <div>
   605→        <div class="s-name">${esc(spriteName)}</div>
   606→        <div class="s-ability">${esc(ability)}</div>
   607→      </div>
   608→      <button class="expand-btn" onclick="toggleLP('lp-${sid}',this)">▼ Level Progression</button>
   609→    </div>
   610→    <div class="level-panel" id="lp-${sid}">
   611→      <div class="level-panel-title">ABILITY PROGRESSION BY LEVEL</div>
   612→      ${levelRows}
   613→    </div>
   614→    ${variantRows}
   615→  </div>`;
   616→}
   617→
   618→function toggleLP(id, btn) {
   619→  const panel = document.getElementById(id);
   620→  const open  = panel.classList.toggle('open');
   621→  btn.textContent = open ? '▲ Level Progression' : '▼ Level Progression';
   622→  btn.classList.toggle('open', open);
   623→}
   624→
   625→function buildVariantRow(row) {
   626→  const key   = row.key;
   627→  const safe  = safeId(key);
   628→  const owned = row.owned;
   629→  const lvl   = row.level;
   630→  const mast  = row.mastered;
   631→  const summ  = row.summoned;
   632→  const perk  = VPERKS[row.variant] || '';
   633→
   634→  // Level buttons — lit up to current level; no special crown style (mastered is separate)
   635→  let lvlBtns = '';
   636→  for (let i = 1; i <= 5; i++) {
   637→    const isLit  = owned && i <= lvl;
   638→    const cls    = isLit ? 'lvl-btn lit' : 'lvl-btn';
   639→    const label  = i === 5 ? '5' : i;
   640→    lvlBtns += `<button class="${cls}" ${owned?'':'disabled'}
   641→      onclick="setLevel('${esc(key)}',${i})" title="Level ${i}">${label}</button>`;
   642→  }
   643→
   644→  // Mastered toggle — auto-forced at level 5
   645→  const mastForced = owned && lvl === 5;
   646→  const mastChecked = owned && mast;
   647→  const mastLblCls  = mastForced ? 'mast-label forced' : (mastChecked ? 'mast-label on' : 'mast-label');
   648→  const mastLblText = mastForced ? '★ (Lv 5)' : (mastChecked ? '★ Yes' : '☆ No');
   649→
   650→  // Status
   651→  const statusHtml = owned && row.status
   652→    ? `<span class="s-status ${row.status.cls}">${row.status.icon} ${esc(row.status.text)}</span>`
   653→    : `<span class="s-unowned">— not collected —</span>`;
   654→
   655→  const rowCls = ['variant-row', owned?'owned':'', (owned&&mast)?'is-mastered':''].filter(Boolean).join(' ');
   656→
   657→  return `<div class="${rowCls}" id="row-${safe}">
   658→    <input type="checkbox" class="own-check" ${owned?'checked':''}
   659→      onchange="toggleOwned('${esc(key)}',this.checked)" title="Mark as owned" />
   660→    <div class="v-col">
   661→      <span class="v-chip v-${esc(row.variant)}">${esc(row.variant)}</span>
   662→      <span class="v-perk">${esc(perk)}</span>
   663→    </div>
   664→    <span class="v-cost ${row.cost>=10000?'hi':''}">💨 ${row.cost.toLocaleString()} Dust</span>
   665→    <div class="lvl-selector" id="lvls-${safe}">${lvlBtns}</div>
   666→    <div class="mast-col" id="mastcol-${safe}">
   667→      <input type="checkbox" class="mast-check" id="mast-${safe}"
   668→        ${mastChecked?'checked':''} ${(!owned||mastForced)?'disabled':''}
   669→        onchange="toggleMastered('${esc(key)}',this.checked)"
   670→        title="${mastForced?'Automatically mastered at Level 5':'Mark as mastered'}" />
   671→      <span class="${mastLblCls}" id="mastlbl-${safe}">${mastLblText}</span>
   672→    </div>
   673→    <div class="s-toggle">
   674→      <label class="tgl">
   675→        <input type="checkbox" id="sum-${safe}" ${summ?'checked':''} ${owned?'':'disabled'}
   676→          onchange="toggleSummoned('${esc(key)}',this.checked)" />
   677→        <span class="tgl-sl"></span>
   678→      </label>
