   801→async function upsert(key, level, summoned, mastered) {
   802→  try {
   803→    const res = await fetch('/api/collection/'+encodeKey(key), {
   804→      method: 'PUT',
   805→      headers: {'Content-Type':'application/json'},
   806→      body: JSON.stringify({level, summoned, mastered})
   807→    });
   808→    if (!res.ok) { const d=await res.json(); showToast(d.error||'Error saving.','err'); return; }
   809→    const row = allRows.find(r => r.key === key);
   810→    if (row) {
   811→      const maxLevel = row.max_level || 5;
   812→      row.owned    = true;
   813→      row.level    = summoned ? level : 1;  // server also enforces this
   814→      row.summoned = summoned;
   815→      row.mastered = mastered || (level === 5 && maxLevel === 5);
